#include<bits/stdc++.h>
using namespace std;
const int MAXN=3e5+5;
long long n,sum,c,a[MAXN],f[MAXN],ans=0;
int main(void){
	cin>>n>>c;
	for(int i=1;i<=n;i++)cin>>a[i],sum+=a[i];
    if(c>0){
		for(int i=1;i<=n;++i){
			f[i]=max(f[i-1],0ll)+a[i];
			ans=max(ans,f[i]);
		}
	}else{
		for(int i=1;i<=n;++i){
			f[i]=min(f[i-1],0ll)+a[i];
			ans=min(ans,f[i]);
		}
	}
	cout<<sum+(c-1)*ans;
	return false;
}
